    public static void main(String[] args) {
        // Process all Java files in the source directory
        Launcher launcher = new Launcher();
        launcher.addInputResource("/workspace/nem");
        launcher.setSourceOutputDirectory("/workspace/nem");
        launcher.getEnvironment().setAutoImports(true);
        launcher.getEnvironment().setComplianceLevel(8);

        // Process the code
        launcher.run();

        // Apply transformations
        applyFlywayTransformation(launcher.getFactory());

        // Write the modified code back to files
        launcher.process();
    }

    public static void applyFlywayTransformation(Factory factory) {
        // Find all Flyway constructor calls with no arguments
        List<CtNewClass> flywayConstructors = factory.getModel().getElements(
            new TypeFilter<>(CtNewClass.class) {
                @Override
                public boolean matches(CtNewClass element) {
                    if (element.getExecutable() != null && element.getExecutable().getDeclaringType() != null) {
                        return element.getExecutable().getDeclaringType().getQualifiedName().equals("org.flywaydb.core.Flyway") &&
                               element.getArguments().size() == 0;
                    }
                    return false;
                }
            }
        );

        for (CtNewClass flywayConstructor : flywayConstructors) {
            // Replace the old constructor with the new fluent API approach
            replaceConstructorWithFluentAPI(factory, flywayConstructor);
        }
    }

    private static void replaceConstructorWithFluentAPI(Factory factory, CtNewClass flywayConstructor) {
        // Create the new expression: Flyway.configure()
        CtTypeReference<?> flywayType = factory.Type().createReference("org.flywaydb.core.Flyway");
        CtExecutableReference<?> configureMethod = factory.Executable().createReference(flywayType, "configure", new ArrayList<>());
        CtInvocation<?> configureCall = factory.Code().createInvocation(null, configureMethod, new ArrayList<>());

        // Replace the constructor call with the fluent API
        flywayConstructor.replace(configureCall);
    }
}

