            CtVariableRead varRead = (CtVariableRead) assignment.getAssigned();
            String varName = varRead.getVariable().getSimpleName();

            // Find all method calls on this variable
            List<CtInvocation<?>> methodCalls = new ArrayList<>();
            findMethodCallsOnVariable(factory, varName, methodCalls);

            // Create the new fluent API call
            replaceWithFluentAPI(factory, assignment, methodCalls);
        }
    }

    private static void findMethodCallsOnVariable(Factory factory, String varName, List<CtInvocation<?>> methodCalls) {
        // Find all method calls that reference the Flyway variable
        List<CtInvocation<?>> allInvocations = factory.Query()
            .select(new TypeFilter<>(CtInvocation.class))
            .filter(inv -> inv.getTarget() instanceof CtVariableRead);

        for (CtInvocation<?> invocation : allInvocations) {
            if (invocation.getTarget() instanceof CtVariableRead) {
                CtVariableRead targetVar = (CtVariableRead) invocation.getTarget();
                if (targetVar.getVariable().getSimpleName().equals(varName)) {
                    methodCalls.add(invocation);
                }
            }
        }
    }

    private static void replaceWithFluentAPI(Factory factory, CtVariableAssignment assignment, List<CtInvocation<?>> methodCalls) {
        // Get the variable being assigned to
        CtVariableRead varRead = (CtVariableRead) assignment.getAssigned();
        String varName = varRead.getVariable().getSimpleName();

        // Create the new expression: Flyway.configure() 
        CtTypeReference<?> flywayType = factory.Type().createReference("org.flywaydb.core.Flyway");
        CtExecutableReference<?> configureMethod = factory.Executable().createReference(flywayType, "configure");
        CtInvocation<?> configureCall = factory.Code().createInvocation(null, configureMethod, new ArrayList<>());

        // Create the new assignment with fluent API
        CtVariableAssignment newAssignment = factory.Core().createVariableAssignment();
        newAssignment.setVariable(assignment.getVariable());
        newAssignment.setAssignment(configureCall);

        // Replace the old assignment
        assignment.replace(newAssignment);

        // Now we need to find and remove the old method calls
        // This would be more complex to fully implement correctly in this context
    }
}

